import{_ as a,o as e,c as i,ae as o}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"脚本工具概述","description":"","frontmatter":{},"headers":[],"relativePath":"zh/settings/tools.md","filePath":"zh/settings/tools.md","lastUpdated":1776650765000}'),l={name:"zh/settings/tools.md"};function s(r,t,n,d,h,p){return e(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="脚本工具概述" tabindex="-1">脚本工具概述 <a class="header-anchor" href="#脚本工具概述" aria-label="Permalink to &quot;脚本工具概述&quot;">​</a></h1><p>EasyYapi 提供了一组内置工具，可在配置规则的 Groovy 脚本中使用。这些工具在所有 Groovy 脚本上下文中自动作为变量可用。</p><h2 id="可用工具" tabindex="-1">可用工具 <a class="header-anchor" href="#可用工具" aria-label="Permalink to &quot;可用工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td><a href="./tools/it">it</a></td><td>当前上下文对象 - 最重要的工具，提供对正在处理元素的访问</td></tr><tr><td><a href="./tools/tool">tool</a></td><td>通用工具方法，用于字符串操作、集合、JSON 等</td></tr><tr><td><a href="./tools/regex">regex</a></td><td>正则表达式工具，带模式缓存以提高性能</td></tr><tr><td><a href="./tools/logger">logger</a></td><td>日志工具，用于调试和信息输出</td></tr><tr><td><a href="./tools/helper">helper</a></td><td>常用操作辅助方法，用于类型解析等</td></tr><tr><td><a href="./tools/httpClient">httpClient</a></td><td>HTTP 客户端，用于在脚本中发送请求</td></tr><tr><td><a href="./tools/localStorage">localStorage</a></td><td>持久化本地存储，IDE 重启后数据保留</td></tr><tr><td><a href="./tools/session">session</a></td><td>会话级存储，IDE 重启后清空</td></tr><tr><td><a href="./tools/config">config</a></td><td>配置访问，用于读取规则值</td></tr><tr><td><a href="./tools/api">api</a></td><td>API 工具，用于修改端点元数据</td></tr><tr><td><a href="./tools/runtime">runtime</a></td><td>运行时环境信息</td></tr><tr><td><a href="./tools/fieldContext">fieldContext</a></td><td>字段上下文工具，用于 JSON 路径操作</td></tr><tr><td><a href="./tools/files">files</a></td><td>文件操作，用于读写文件</td></tr></tbody></table><h2 id="用法" tabindex="-1">用法 <a class="header-anchor" href="#用法" aria-label="Permalink to &quot;用法&quot;">​</a></h2><p>工具在 Groovy 脚本中作为变量使用：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.mock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">if (it.type().name() == &quot;java.lang.String&quot;) {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return &quot;mock_string&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">logger.info(&quot;Generating mock for: &quot; + it.name())</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><h2 id="工具分类" tabindex="-1">工具分类 <a class="header-anchor" href="#工具分类" aria-label="Permalink to &quot;工具分类&quot;">​</a></h2><h3 id="上下文工具" tabindex="-1">上下文工具 <a class="header-anchor" href="#上下文工具" aria-label="Permalink to &quot;上下文工具&quot;">​</a></h3><ul><li><strong>it</strong> - 主要的上下文对象。其类型取决于规则上下文： <ul><li>类规则 → <code>ScriptPsiClassContext</code></li><li>方法规则 → <code>ScriptPsiMethodContext</code></li><li>字段规则 → <code>ScriptPsiFieldContext</code></li><li>参数规则 → <code>ScriptPsiParameterContext</code></li></ul></li></ul><h3 id="存储工具" tabindex="-1">存储工具 <a class="header-anchor" href="#存储工具" aria-label="Permalink to &quot;存储工具&quot;">​</a></h3><ul><li><strong>localStorage</strong> - 持久化存储，IDE 重启后数据保留</li><li><strong>session</strong> - 临时存储，IDE 重启后清空</li></ul><h3 id="实用工具" tabindex="-1">实用工具 <a class="header-anchor" href="#实用工具" aria-label="Permalink to &quot;实用工具&quot;">​</a></h3><ul><li><strong>tool</strong> - 字符串操作、集合、JSON 操作</li><li><strong>regex</strong> - 正则表达式匹配和提取</li><li><strong>helper</strong> - 类型解析和常用操作</li><li><strong>files</strong> - 文件 I/O 操作</li></ul><h3 id="通信工具" tabindex="-1">通信工具 <a class="header-anchor" href="#通信工具" aria-label="Permalink to &quot;通信工具&quot;">​</a></h3><ul><li><strong>httpClient</strong> - HTTP 请求</li><li><strong>config</strong> - 配置访问</li><li><strong>api</strong> - API 端点修改</li></ul><h3 id="信息工具" tabindex="-1">信息工具 <a class="header-anchor" href="#信息工具" aria-label="Permalink to &quot;信息工具&quot;">​</a></h3><ul><li><strong>logger</strong> - 日志输出</li><li><strong>runtime</strong> - 环境信息</li><li><strong>fieldContext</strong> - JSON 路径上下文</li></ul><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../config-rule">配置规则</a> - 如何在配置规则中使用工具</li><li><a href="./../events/">事件</a> - 可以使用脚本的事件钩子</li></ul>`,20)])])}const u=a(l,[["render",s]]);export{g as __pageData,u as default};
